// @grant        GM_addElement
// @grant        GM_addStyle
// ==/UserScript==

const urlParams = new URLSearchParams(window.location.search);
const debug = urlParams.get('debug');

(function() {
    'use strict';
    const showPostage = urlParams.get('showPostage');

    if(showPostage == 0){
        return;
        window.location.href = window.location.origin + window.location.pathname + window.location.search.replace('showPostage=0', 'showPostage=1');
    }
    // Your code here...
})();

(function() {

    const urlParams = new URLSearchParams(window.location.search);
    let status = parseInt(urlParams.get('status'));
    let textCss = 'img.bumkidsWaterMark {z-index: 1; filter: brightness(1.4) grayscale(1); width: 77px; margin: 5px; position: absolute; top: 32%; left: 5%;}';

    textCss += 'div.mainPrints > #block_2.a7 {display:none;}';
    textCss += 'div.mainPrints > #receiver { background: white; white-space: nowrap; z-index: 100; font-weight: 900; font-size: 26px !important; height: 28px !important; width: 65% !important;  }';
    textCss += 'div#province {font-size: 200%; }';
    textCss += 'div#qr_code { padding: 3px; top: unset; left: unset; right: 10px; bottom: 75px; width: 100px; height: auto; z-index: 2147483647; background-color: white; }';
    textCss += '  div#product_name { font-size: 110%; font-weight: 900; height: fit-content; max-height: calc(34px); width: calc(100% - 20px); background: white; padding: 5px 10px; left: 0px; display: -webkit-box; -webkit-line-clamp: 3; -webkit-box-orient: vertical; overflow: hidden; text-overflow: ellipsis; }  ';

    GM_addElement(document.body, 'style', {  textContent: textCss   });

    let addBumKidsWaterMark = 1
    addBumKidsWaterMark && document.querySelectorAll('div.mainPrints').forEach(e => {
        GM_addElement(e, 'img', {
            src: 'data:image/bmp;base64,',
            class: 'bumkidsWaterMark'
        });
    });

    let addShippingNote = 0;
    addShippingNote && document.querySelectorAll('div.mainPrints').forEach(e => {
        let txt = GM_addElement(e, 'div', {
            class: 'shippingNote',
            style: 'position: absolute; bottom: 0em; font-size: 1.35em; font-weight: 900; background: white; line-height: 3em; padding: 0 1em;'
        });
        txt.innerHTML = 'KHÔNG ĐỒNG KIỂM / KHÔNG THỬ HÀNG';
    });
})();


(function() {
    'use strict';
    var isClick = false;
    var isPrinted = 0;

    window.addEventListener('click', function(){
        isClick = true;
        document.body.style.background = 'grey';
    });

    window.onafterprint = function(){
        isPrinted = 1;
        //alert('onafterprint');
    }

    let interval = window.setInterval(function(){
        if(!isPrinted){ return false }
        clearInterval(interval);
        return setTimeout(function(){
            (!isClick && !debug) && window.close();
        }, 1000);
    }, 500);


    document.querySelectorAll('div.mainPrints > div#product_name').forEach(itemsName => {
        itemsName.innerText = itemsName.innerText.replace('(1) 1 x ','');
    });

    document.querySelectorAll('div.mainPrints > #receiver').forEach(namePhone => {
        namePhone?.classList.add('name_phone');
        namePhone.innerText = namePhone.innerText?.replace(/(\s*\/\s\d+\*+\d+)/g, '');
        //let phone = namePhone?.innerText.match(/\d+/g)?.pop();
    });

    document.querySelectorAll('div.mainPrints > #receiver').forEach(namePhone => {
        namePhone?.classList.add('name_phone');
        namePhone.innerText = namePhone.innerText?.replace(/(\s*\/\s\d+\*+\d+)/g, '');
    });

    setTimeout(function () {
        return window.print();

        if(debug) return false;
        let mainPrint = document.querySelectorAll('div.mainPrints');
        let phoneBarcode = document.querySelectorAll('img.phoneBarCode');
        if(mainPrint.length == phoneBarcode.length){
            window.print();
        } else {
            setTimeout(_ => window.location.reload(), 2000);
        }
    }, 500);

})();
